### Bad: O(n²)
```js
const matches = arr1.filter(x => arr2.includes(x));
```
### Good: O(n)
```js
const set2 = new Set(arr2);
const matches = arr1.filter(x => set2.has(x));
```
Set.has() is O(1) vs Array.includes() which is O(n).

### Bad
```js
const results = [];
for (let i = 0; i < items.length; i++) {
  results.push(items[i].value * 2);
}
```
### Good
```js
const results = items.map(item => item.value * 2);
```
.map() returns a new array without mutating the original.

### Bad
```js
const active = [];
for (const user of users) {
  if (user.isActive) active.push(user);
}
```
### Good
```js
const active = users.filter(user => user.isActive);
```
Chain .filter() and .map() together for powerful pipelines.

### Bad
```js
let total = 0;
for (const item of cart) {
  total += item.price;
}
```
### Good
```js
const total = cart.reduce((sum, item) => sum + item.price, 0);
```
Also useful for grouping: reduce into an object or Map.

### Bad: O(n) per lookup
```js
function getUser(id) {
  return users.find(u => u.id === id);
}
```
### Good: O(1) per lookup
```js
const userMap = new Map(users.map(u => [u.id, u]));
function getUser(id) {
  return userMap.get(id);
}
```
Build once, query many times efficiently.

### Finding a pair that sums to target:
```js
function hasPairWithSum(arr, target) {
  let left = 0, right = arr.length - 1;
  while (left < right) {
    const sum = arr[left] + arr[right];
    if (sum === target) return true;
    else if (sum < target) left++;
    else right--;
  }
  return false;
}
```
No nested loop needed — linear time.

### Max sum of k consecutive elements:
```js
function maxSum(arr, k) {
  let sum = arr.slice(0, k).reduce((a, b) => a + b, 0);
  let max = sum;
  for (let i = k; i < arr.length; i++) {
    sum += arr[i] - arr[i - k];
    max = Math.max(max, sum);
  }
  return max;
}
```
Slide the window instead of recomputing from scratch.

### Fibonacci without memoization: O(2^n)
```js
function fib(n) {
  if (n <= 1) return n;
  return fib(n - 1) + fib(n - 2);
}
```
### With memoization: O(n)
```js
const memo = {};
function fib(n) {
  if (n in memo) return memo[n];
  if (n <= 1) return n;
  return (memo[n] = fib(n - 1) + fib(n - 2));
}
```

