### Messy Promise Chain
```js
getUser(id)
  .then(user => getPosts(user.id))
  .then(posts => render(posts))
  .catch(err => console.error(err));
```
### Clean Async/Await
```js
async function loadPosts(id) {
  try {
    const user = await getUser(id);
    const posts = await getPosts(user.id);
    render(posts);
  } catch (err) {
    console.error(err);
  }
}
```

### Simple debounce implementation
```js
function debounce(fn, delay) {
  let timer;
  return function(...args) {
    clearTimeout(timer);
    timer = setTimeout(() => fn.apply(this, args), delay);
  };
}

const onSearch = debounce((query) => fetchResults(query), 300);
input.addEventListener('input', e => onSearch(e.target.value));
```
The API call only fires 300ms after the user stops typing.

### Deeply Nested (Hard to read)
```js
function process(user) {
  if (user) {
    if (user.isActive) {
      if (user.hasPermission) {
        doWork(user);
      }
    }
  }
}
```
### Early Returns (Clean)
```js
function process(user) {
  if (!user) return;
  if (!user.isActive) return;
  if (!user.hasPermission) return;
  doWork(user);
}
```

### Without Destructuring
```js
function greet(user) {
  console.log(user.firstName + ' ' + user.lastName);
  console.log(user.email);
}
```
### With Destructuring
```js
function greet({ firstName, lastName, email }) {
  console.log(`${firstName} ${lastName}`);
  console.log(email);
}
```
Also works for arrays: `const [first, second] = arr;`

```js
const CONFIG = Object.freeze({
  API_URL: 'https://api.example.com',
  TIMEOUT: 5000,
  MAX_RETRIES: 3
});

// This will silently fail (or throw in strict mode):
CONFIG.API_URL = 'https://evil.com'; // No effect!
```
Use for app-wide constants to prevent hard-to-find mutation bugs.

### Why var is dangerous
```js
for (var i = 0; i < 3; i++) {
  setTimeout(() => console.log(i), 100);
}
// Prints: 3 3 3 (not 0 1 2!)
```
### Why let/const fix it
```js
for (let i = 0; i < 3; i++) {
  setTimeout(() => console.log(i), 100);
}
// Prints: 0 1 2
```
let and const are block-scoped — no surprises.

### Repeated code is a maintenance trap
```js
// Component A
const formatted = value.toFixed(2) + '$';

// Component B
const formatted = amount.toFixed(2) + '$';
```
### Extract once, use everywhere
```js
function formatCurrency(value) {
  return value.toFixed(2) + '$';
}
// Both components now call formatCurrency()
```

### Bad: Re-computes every render
```jsx
function Component({ items }) {
  const sorted = items.sort((a, b) => a.name.localeCompare(b.name));
  return <List items={sorted} />;
}
```
### Good: Only re-computes when items changes
```jsx
function Component({ items }) {
  const sorted = useMemo(
    () => [...items].sort((a, b) => a.name.localeCompare(b.name)),
    [items]
  );
  return <List items={sorted} />;
}
```

### Without useCallback
```jsx
// handleClick is re-created every render!
function Parent() {
  const handleClick = () => doSomething();
  return <Child onClick={handleClick} />;
}
```
### With useCallback
```jsx
function Parent() {
  const handleClick = useCallback(() => doSomething(), []);
  return <Child onClick={handleClick} />;
}
// Child does not re-render unless handleClick changes
```

### Linear Search: O(n)
```js
function find(arr, target) {
  return arr.indexOf(target); // Scans every element
}
```
### Binary Search: O(log n)
```js
function binarySearch(arr, target) {
  let low = 0, high = arr.length - 1;
  while (low <= high) {
    const mid = Math.floor((low + high) / 2);
    if (arr[mid] === target) return mid;
    else if (arr[mid] < target) low = mid + 1;
    else high = mid - 1;
  }
  return -1;
}
```

### Mutation bug
```js
const user = { name: 'Ali', score: 10 };
function addScore(u, points) {
  u.score += points; // Mutates original!
  return u;
}
```
### Safe immutable update
```js
function addScore(u, points) {
  return { ...u, score: u.score + points }; // New object
}
```
In arrays, use .map(), .filter(), [...arr] instead of .push() or splice.

